376	        for(long in_x = -pad_x, out_x = 0; out_x < out_tensor_dim_x; in_x += stride_x, out_x++)
377	        {
378	            long cur_ch = 0;
379	            long ker_x_start = MAX(0, -in_x);
380	            q31_t *pBias = (q31_t*)bias;
