31	static void conv_dw_HWC_s8_any_mult_4(const int8_t *in_tensor,
32	                                     const int32_t in_tensor_dim_x,
33	                                     const int32_t in_tensor_dim_y,
34	                                     const int32_t in_tensor_ch,
35	                                     const int8_t *ker_weight,
36	                                     const int32_t out_tensor_ch,
37	                                     const int32_t ch_mult,
38	                                     const int32_t ker_dim_x,
39	                                     const int32_t ker_dim_y,
40	                                     const int32_t pad_x,
41	                                     const int32_t pad_y,
42	                                     const int32_t stride_x,
43	                                     const int32_t stride_y,
44	                                     const int32_t *bias,
45	                                     int8_t *out_tensor,
46	                                     const int32_t *out_shift,
47	                                     const int32_t *out_scale,
48	                                     const int32_t out_tensor_dim_x,
49	                                     const int32_t out_tensor_dim_y,
50	                                     const int32_t out_offset,  //value is in the range of [-127, 128]
51	                                     const int32_t in_offset,   //value is in the range of [-128, 127]
52	                                     const int32_t act_min,
53	                                     const int32_t act_max)
54	{
55	#ifdef ENA_DSP_ISA_64
56	    for(int32_t in_h = -pad_y, out_h = 0, out_idx = 0; out_h < out_tensor_dim_y; in_h += stride_y, ++out_h)
57	    {
58	        for(int32_t in_w = -pad_x, out_w = 0, ker_h_start = MAX(0, -in_h); out_w < out_tensor_dim_x; in_w += stride_x, ++out_w)
59	        {
60	            for(int32_t in_ch = 0, out_ch = 0, ker_w_start = MAX(0, -in_w); in_ch < in_tensor_ch; ++in_ch, out_ch += ch_mult)
61	            {
62	                int mult_tile = 0;
63	                for(; (mult_tile + SIMD_NUM_Q7) <= ch_mult; mult_tile += SIMD_NUM_Q7)
64	                {
65	                    int32_t out_buff_s32_0, out_buff_s32_1, out_buff_s32_2, out_buff_s32_3,
66	                            out_buff_s32_4, out_buff_s32_5, out_buff_s32_6, out_buff_s32_7;
67	
68	                    const int32_t *ptr_bias = &bias[out_ch + mult_tile];
69	                    long out_buff40 = 0;
70	                    long out_buff51 = 0;
71	                    long out_buff62 = 0;
72	                    long out_buff73 = 0;
73	                    if (bias)
74	                    {
75	                        out_buff40 = NDS_DSP_PKBB32(*(ptr_bias+4), *ptr_bias);
76	                        out_buff51 = NDS_DSP_PKBB32(*(ptr_bias+5), *(ptr_bias+1));
77	                        out_buff62 = NDS_DSP_PKBB32(*(ptr_bias+6), *(ptr_bias+2));
78	                        out_buff73 = NDS_DSP_PKBB32(*(ptr_bias+7), *(ptr_bias+3));
79	                    }
80	
81	                    for(int32_t ker_h = ker_h_start; ker_h < MIN(ker_dim_y, in_tensor_dim_y - in_h); ++ker_h)
82	                    {
83	                        int32_t ker_idx = ker_h * (out_tensor_ch * ker_dim_x) + ker_w_start * out_tensor_ch + out_ch;
84	                        int32_t in_idx  = (in_h + ker_h) * (in_tensor_ch * in_tensor_dim_x) + in_w * in_tensor_ch + in_ch;
85	
86	                        for(int32_t ker_w = ker_w_start; ker_w < MIN(ker_dim_x, in_tensor_dim_x - in_w); ++ker_w, ker_idx += out_tensor_ch)
87	                        {
88	                            long in_val = in_tensor[in_idx + ker_w * in_tensor_ch] + in_offset;
89	                            long in_val_dual = NDS_DSP_PKBB32(in_val, in_val);
90	
91	                            const int8_t *pWt = &ker_weight[ker_idx + mult_tile];
92	                            suni_t wt_val_s8 = simd_load_8((s8_t*)pWt, 0);
93	                            long wt_val_s16_0 = NDS_DSP_SUNPKD820(wt_val_s8.l0);
94	                            long wt_val_s16_1 = NDS_DSP_SUNPKD831(wt_val_s8.l0);
95	
96	                            out_buff40 = NDS_DSP_KMABB(out_buff40, in_val_dual, wt_val_s16_0);
97	                            out_buff51 = NDS_DSP_KMABB(out_buff51, in_val_dual, wt_val_s16_1);
98	                            out_buff62 = NDS_DSP_KMABT(out_buff62, in_val_dual, wt_val_s16_0);
99	                            out_buff73 = NDS_DSP_KMABT(out_buff73, in_val_dual, wt_val_s16_1);
100	                        }
101	                    }
102	
103	                    out_buff_s32_0 = out_buff40;
104	                    out_buff_s32_1 = out_buff51;
105	                    out_buff_s32_2 = out_buff62;
106	                    out_buff_s32_3 = out_buff73;
107	                    out_buff_s32_4 = out_buff40 >> 32;
108	                    out_buff_s32_5 = out_buff51 >> 32;
109	                    out_buff_s32_6 = out_buff62 >> 32;
110	                    out_buff_s32_7 = out_buff73 >> 32;
111	
112	                    out_buff_s32_0 = nn_requantize(out_buff_s32_0, out_scale[out_ch + 0 + mult_tile], out_shift[out_ch + 0 + mult_tile]);
113	                    out_buff_s32_1 = nn_requantize(out_buff_s32_1, out_scale[out_ch + 1 + mult_tile], out_shift[out_ch + 1 + mult_tile]);
114	                    out_buff_s32_2 = nn_requantize(out_buff_s32_2, out_scale[out_ch + 2 + mult_tile], out_shift[out_ch + 2 + mult_tile]);
115	                    out_buff_s32_3 = nn_requantize(out_buff_s32_3, out_scale[out_ch + 3 + mult_tile], out_shift[out_ch + 3 + mult_tile]);
116	                    out_buff_s32_4 = nn_requantize(out_buff_s32_4, out_scale[out_ch + 4 + mult_tile], out_shift[out_ch + 4 + mult_tile]);
117	                    out_buff_s32_5 = nn_requantize(out_buff_s32_5, out_scale[out_ch + 5 + mult_tile], out_shift[out_ch + 5 + mult_tile]);
118	                    out_buff_s32_6 = nn_requantize(out_buff_s32_6, out_scale[out_ch + 6 + mult_tile], out_shift[out_ch + 6 + mult_tile]);
119	                    out_buff_s32_7 = nn_requantize(out_buff_s32_7, out_scale[out_ch + 7 + mult_tile], out_shift[out_ch + 7 + mult_tile]);
120	
121	                    out_buff40 = NDS_DSP_PKBB32(out_buff_s32_4, out_buff_s32_0);
122	                    out_buff51 = NDS_DSP_PKBB32(out_buff_s32_5, out_buff_s32_1);
123	                    out_buff62 = NDS_DSP_PKBB32(out_buff_s32_6, out_buff_s32_2);
124	                    out_buff73 = NDS_DSP_PKBB32(out_buff_s32_7, out_buff_s32_3);
125	
126	                    long output_offset_dual = NDS_DSP_PKBB32(out_offset, out_offset);
127	                    out_buff40 = NDS_DSP_ADD32(out_buff40, output_offset_dual);
128	                    out_buff51 = NDS_DSP_ADD32(out_buff51, output_offset_dual);
129	                    out_buff62 = NDS_DSP_ADD32(out_buff62, output_offset_dual);
130	                    out_buff73 = NDS_DSP_ADD32(out_buff73, output_offset_dual);
131	
132	                    long out_act_min_dual = NDS_DSP_PKBB32(act_min, act_min);
133	                    long out_act_max_dual = NDS_DSP_PKBB32(act_max, act_max);
134	                    out_buff40 = NDS_DSP_SMAX32(out_buff40, out_act_min_dual);
135	                    out_buff40 = NDS_DSP_SMIN32(out_buff40, out_act_max_dual);
136	                    out_buff51 = NDS_DSP_SMAX32(out_buff51, out_act_min_dual);
137	                    out_buff51 = NDS_DSP_SMIN32(out_buff51, out_act_max_dual);
138	                    out_buff62 = NDS_DSP_SMAX32(out_buff62, out_act_min_dual);
139	                    out_buff62 = NDS_DSP_SMIN32(out_buff62, out_act_max_dual);
140	                    out_buff73 = NDS_DSP_SMAX32(out_buff73, out_act_min_dual);
141	                    out_buff73 = NDS_DSP_SMIN32(out_buff73, out_act_max_dual);
142	
143	#if 1
